async function viewFile(path) {
    const modal = document.getElementById('viewer-modal');
    const content = document.getElementById('viewer-content');
    modal.style.display = 'flex';

    const isEncrypted = path.endsWith('.ctx');
    const isImage = path.toLowerCase().match(/\.(jpg|jpeg|png|gif|webp)$/);
    const isAudio = path.toLowerCase().match(/\.(m4a|mp3|wav)$/);

    content.innerHTML = isEncrypted 
        ? '<div style="text-align:center; padding:40px; color:var(--primary)">DECRYPTING_SECURE_BLOB...</div>'
        : '<div style="text-align:center; padding:40px;">RETRIEVING_BINARY_STREAM...</div>';

    try {
        const resp = await fetch(`${SUPABASE_URL}/storage/v1/object/cortex-vault/${path}`, {
            headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
        });

        if (!resp.ok) throw new Error("HTTP_ERROR_" + resp.status);

        if (isImage) {
            const blob = await resp.blob();
            const url = URL.createObjectURL(blob);
            content.innerHTML = `<img src="${url}" style="width:100%; border:1px solid #333; border-radius:4px;" onload="window.lastBlobUrl='${url}'">`;
            return;
        }

        if (isAudio) {
            const blob = await resp.blob();
            const url = URL.createObjectURL(blob);
            content.innerHTML = `
                <div style="padding:40px; text-align:center;">
                    <div style="margin-bottom:20px; color:var(--secondary)">AUDIO_CLIP_READY</div>
                    <audio controls src="${url}" style="width:100%" onplay="window.lastBlobUrl='${url}'"></audio>
                </div>`;
            return;
        }

function closeViewer() {
    document.getElementById('viewer-modal').style.display = 'none';
    if (window.lastBlobUrl) {
        URL.revokeObjectURL(window.lastBlobUrl);
        window.lastBlobUrl = null;
    }
}
